function WeightSlider({ label, value, color }) {
  // Hard constraint: bound between 0 and 100
  const percentage = Math.max(0, Math.min(100, Math.round(value)));

  return (
    <div>
      <div className="flex justify-between mb-1">
        <span className="text-sm font-medium text-slate-300">{label}</span>
        <span className="text-sm text-slate-400">{percentage}%</span>
      </div>
      <div className="w-full bg-dark-900 rounded-full h-1.5 border border-white/5 overflow-hidden">
        <div 
          className={`h-1.5 rounded-full ${color} shadow-[0_0_8px_currentColor] transition-all duration-700 ease-out`} 
          style={{ width: `${percentage}%` }}
        ></div>
      </div>
    </div>
  )
}

